// // This module compares two 64-bit signed integers and outputs whether the first is less than or equal to the second.
module comparator_64bit (  
    input [63:0] a,  
    input [63:0] b,  
    output reg greater,  
    output reg equal,  
    output reg less  
);  
    always @(*) begin  
        if (a > b) begin  
            greater = 1;  
            equal = 0;  
            less = 0;  
        end else if (a < b) begin  
            greater = 0;  
            equal = 0;  
            less = 1;  
        end else begin  
            greater = 0;  
            equal = 1;  
            less = 0;  
        end  
    end  
endmodule
